INSERT INTO "public"."knowledge" ("uuid", "opd_id", "title", "content", "category", "tags", "priority", "language", "status", "source", "attachment_url", "created_by", "updated_by", "created_at", "updated_at", "ai_summary", "ai_keywords", "ai_tags", "example_questions", "example_answers", "confidence_score", "is_official", "allow_ai_direct_answer", "need_human_escalation", "related_opd", "official_references", "reference_url", "metadata", "embedding_status", "embedding_updated_at", "chunk_index", "chunk_hash") VALUES ('0dfe672b-6261-47cb-acfe-8f3c6f450443', 'BPN', 'Prosedur Pengecekan Sertifikat Tanah Asli atau Palsu', 'Untuk memastikan keaslian sertifikat tanah, masyarakat dapat mengajukan permohonan pengecekan sertifikat (SMS/plotting) di Kantor Pertanahan (BPN) Bojonegoro dengan membawa fotokopi sertifikat dan KTP pemilik. Proses pengecekan juga bisa dilakukan secara online melalui aplikasi Sentuh Tanahku. Biaya pengecekan sertifikat sesuai PP No. 128 Tahun 2015 sekitar Rp50.000 per bidang. Hasil pengecekan biasanya keluar dalam 1-3 hari kerja.', 'Pertanahan', ARRAY['sertifikat tanah','bpn','plotting','cek keaslian'], 3, 'id', 'published', 'manual_input', null, null, null, '2026-06-07 09:01:41.738917+00', '2026-07-07 09:01:41.738917+00', 'Cara mengecek keaslian sertifikat tanah melalui BPN Bojonegoro baik offline maupun aplikasi Sentuh Tanahku.', ARRAY['sertifikat tanah','bpn','sentuh tanahku','plotting tanah'], ARRAY['pertanahan','legalitas'], ARRAY['Bagaimana cara cek sertifikat tanah asli?','Berapa biaya cek sertifikat di BPN?','Apakah bisa cek sertifikat online?'], ARRAY['Bawa fotokopi sertifikat dan KTP ke Kantor BPN Bojonegoro, atau cek online lewat aplikasi Sentuh Tanahku.','Biaya sekitar Rp50.000 per bidang, hasil keluar 1-3 hari kerja.'], 88, true, true, false, ARRAY['BPN'], ARRAY['PP No. 128 Tahun 2015 tentang Jenis dan Tarif PNBP Kementerian ATR/BPN'], 'https://bpn.bojonegorokab.go.id/pengecekan-sertifikat', '{"biaya":"Rp50.000/bidang","estimasi_selesai":"1-3 hari kerja"}', 'completed', '2026-07-07 09:01:41.738917+00', 0, 'd4e5f6a7b8c90004'), ('1c88042f-0bf1-486f-81ef-ab9ce100a039', 'DPMPTSP', 'Cara Mengurus NIB (Nomor Induk Berusaha) via OSS', 'Nomor Induk Berusaha (NIB) adalah identitas pelaku usaha yang wajib dimiliki untuk menjalankan usaha secara legal. Pendaftaran dilakukan online melalui sistem OSS (Online Single Submission) di oss.go.id. Dokumen yang diperlukan: KTP, NPWP, dan data usaha (jenis usaha, lokasi, modal). Setelah pendaftaran online berhasil, pelaku usaha bisa berkonsultasi ke kantor DPMPTSP Bojonegoro jika mengalami kendala teknis. NIB berlaku selama usaha masih berjalan tanpa perlu diperpanjang.', 'Perizinan Usaha', ARRAY['nib','izin usaha','oss','umkm'], 4, 'id', 'published', 'manual_input', null, null, null, '2026-06-22 09:01:41.738917+00', '2026-07-12 09:01:41.738917+00', 'Panduan pendaftaran NIB secara online melalui sistem OSS bagi pelaku usaha di Bojonegoro.', ARRAY['nib','oss','izin usaha','umkm','dpmptsp'], ARRAY['perizinan','ekonomi','umkm'], ARRAY['Bagaimana cara dapat NIB?','Apa itu OSS?','Syarat daftar izin usaha apa saja?'], ARRAY['NIB didaftarkan online lewat oss.go.id menggunakan KTP, NPWP, dan data usaha Anda.','Kalau ada kendala teknis, bisa konsultasi langsung ke kantor DPMPTSP Bojonegoro.'], 92, true, true, false, ARRAY['DPMPTSP'], ARRAY['PP No. 5 Tahun 2021 tentang Penyelenggaraan Perizinan Berusaha Berbasis Risiko'], 'https://dpmptsp.bojonegorokab.go.id/layanan/nib', '{"biaya":"gratis","berlaku":"selama usaha berjalan","platform":"oss.go.id"}', 'completed', '2026-07-12 09:01:41.738917+00', 0, 'b2c3d4e5f6a70002'), ('407ee7f0-66be-4612-8f86-b15e79d16ffc', 'BAPENDA', 'Cara Bayar dan Cek Tunggakan PBB-P2 Online', 'Pajak Bumi dan Bangunan Perdesaan dan Perkotaan (PBB-P2) dapat dicek dan dibayar secara online melalui aplikasi atau website resmi Bapenda Kabupaten Bojonegoro dengan memasukkan Nomor Objek Pajak (NOP). Pembayaran juga bisa dilakukan melalui teller bank, ATM, atau minimarket yang bekerja sama. Batas waktu pembayaran PBB biasanya jatuh setiap tanggal 30 September tiap tahunnya. Keterlambatan pembayaran dikenakan denda administrasi sebesar 2% per bulan dari pokok pajak.', 'Pajak Daerah', ARRAY['pbb','pajak','nop','tunggakan'], 4, 'id', 'published', 'manual_input', null, null, null, '2026-06-27 09:01:41.738917+00', '2026-07-16 09:01:41.738917+00', 'Panduan cek dan pembayaran PBB-P2 secara online serta informasi denda keterlambatan.', ARRAY['pbb-p2','pajak bumi bangunan','nop','bapenda bojonegoro'], ARRAY['pajak-daerah','keuangan'], ARRAY['Bagaimana cara bayar PBB online?','Kalau telat bayar PBB kena denda berapa?','Cara cek tunggakan pajak bumi?'], ARRAY['Masukkan Nomor Objek Pajak (NOP) Anda di aplikasi/website resmi Bapenda untuk cek dan bayar PBB.','Batas waktu pembayaran setiap 30 September, telat kena denda 2% per bulan.'], 90, true, true, false, ARRAY['BAPENDA'], ARRAY['Perda Kabupaten Bojonegoro tentang Pajak Daerah'], 'https://bapenda.bojonegorokab.go.id/pbb', '{"batas_bayar":"30 September","denda_per_bulan":"2%"}', 'completed', '2026-07-16 09:01:41.738917+00', 0, 'c3d4e5f6a7b80003'), ('4b9ae860-02ea-4eef-90b0-09b5c60c9216', 'DINKES', 'Jadwal dan Lokasi Layanan Vaksinasi di Puskesmas Bojonegoro', 'Layanan vaksinasi rutin (imunisasi dasar anak, vaksin booster COVID-19, dan vaksin lainnya) tersedia di seluruh Puskesmas se-Kabupaten Bojonegoro setiap hari kerja pukul 08.00-12.00 WIB. Masyarakat cukup membawa KTP/KK dan buku KIA (untuk anak). Layanan ini gratis tanpa biaya. Untuk jadwal posyandu di tingkat desa, silakan hubungi bidan desa atau kader posyandu setempat.', 'Kesehatan', ARRAY['vaksinasi','imunisasi','puskesmas','posyandu'], 4, 'id', 'published', 'manual_input', null, null, null, '2026-07-02 09:01:41.738917+00', '2026-07-14 09:01:41.738917+00', 'Informasi jadwal, lokasi, dan syarat layanan vaksinasi gratis di Puskesmas se-Bojonegoro.', ARRAY['vaksinasi','imunisasi anak','puskesmas bojonegoro','posyandu'], ARRAY['kesehatan','layanan-gratis'], ARRAY['Vaksin di puskesmas jam berapa?','Syarat vaksinasi anak apa saja?','Vaksin booster gratis tidak?'], ARRAY['Layanan vaksinasi buka setiap hari kerja pukul 08.00-12.00 di seluruh Puskesmas Bojonegoro, gratis.','Cukup bawa KTP/KK dan buku KIA untuk anak.'], 93, true, true, false, ARRAY['DINKES'], ARRAY['Permenkes No. 12 Tahun 2017 tentang Penyelenggaraan Imunisasi'], 'https://dinkes.bojonegorokab.go.id/layanan/vaksinasi', '{"biaya":"gratis","jam_layanan":"08.00-12.00"}', 'completed', '2026-07-14 09:01:41.738917+00', 0, 'e5f6a7b8c9d10005'), ('5ccb2602-2cd0-4644-8af1-df470483a50b', 'DINKES', 'Alur Rujukan Berjenjang BPJS Kesehatan dari Puskesmas ke Rumah Sakit', 'Peserta BPJS Kesehatan wajib mengikuti alur rujukan berjenjang: dimulai dari Fasilitas Kesehatan Tingkat Pertama (FKTP)/Puskesmas tempat terdaftar, baru kemudian dirujuk ke Rumah Sakit jika diperlukan penanganan lebih lanjut sesuai indikasi medis. Rujukan berlaku selama 90 hari dan bisa diperpanjang jika pengobatan masih berlangsung. Dalam kondisi gawat darurat, peserta bisa langsung ke IGD rumah sakit terdekat tanpa rujukan.', 'Kesehatan', ARRAY['bpjs','rujukan','fktp','puskesmas'], 4, 'id', 'published', 'manual_input', null, null, null, '2026-06-19 09:01:41.738917+00', '2026-07-08 09:01:41.738917+00', 'Penjelasan alur rujukan berjenjang BPJS Kesehatan dari Puskesmas ke rumah sakit serta pengecualian kondisi darurat.', ARRAY['bpjs kesehatan','rujukan berjenjang','fktp','igd'], ARRAY['kesehatan','bpjs'], ARRAY['Cara rujukan BPJS ke rumah sakit gimana?','Rujukan BPJS berlaku berapa lama?','Kalau darurat harus ada rujukan tidak?'], ARRAY['Rujukan dimulai dari Puskesmas/FKTP tempat Anda terdaftar, baru dirujuk ke rumah sakit sesuai indikasi medis.','Rujukan berlaku 90 hari; kondisi gawat darurat bisa langsung ke IGD tanpa rujukan.'], 89, true, true, false, ARRAY['DINKES'], ARRAY['Peraturan BPJS Kesehatan No. 2 Tahun 2018 tentang Pelayanan Kesehatan'], 'https://dinkes.bojonegorokab.go.id/layanan/rujukan-bpjs', '{"masa_berlaku_rujukan":"90 hari"}', 'completed', '2026-07-08 09:01:41.738917+00', 0, 'd0e1f2a3b4c50010'), ('6b19fd93-bc9b-42be-b891-e2f6c435878d', 'POLRES', 'Syarat dan Cara Membuat SKCK di Polres Bojonegoro', 'Surat Keterangan Catatan Kepolisian (SKCK) diperlukan untuk melamar kerja, mendaftar sekolah/kuliah, atau keperluan administrasi lainnya. Syarat: fotokopi KTP, fotokopi KK, pas foto berwarna 4x6 (background merah) sebanyak 4 lembar, dan rumus sidik jari dari unit Identifikasi Polres (jika belum punya, bisa langsung ambil sidik jari di tempat). SKCK berlaku selama 6 bulan sejak diterbitkan. Biaya pembuatan sesuai PP adalah Rp30.000, dibayarkan melalui loket BRI di lokasi pelayanan.', 'Keamanan dan Ketertiban', ARRAY['skck','catatan kepolisian','sidik jari'], 4, 'id', 'published', 'manual_input', null, null, null, '2026-06-29 09:01:41.738917+00', '2026-07-11 09:01:41.738917+00', 'Panduan syarat, biaya, dan masa berlaku pembuatan SKCK di Polres Bojonegoro.', ARRAY['skck','polres bojonegoro','sidik jari','surat kelakuan baik'], ARRAY['keamanan','administrasi'], ARRAY['Syarat bikin SKCK apa saja?','SKCK berlaku berapa lama?','Bayar SKCK berapa?'], ARRAY['Siapkan fotokopi KTP, KK, pas foto 4x6 background merah 4 lembar, dan rumus sidik jari.','SKCK berlaku 6 bulan, biaya Rp30.000 dibayar via loket BRI.'], 91, true, true, false, ARRAY['POLRES'], ARRAY['PP No. 60 Tahun 2016 tentang Jenis dan Tarif PNBP Polri'], 'https://polresbojonegoro.jatim.polri.go.id/layanan/skck', '{"biaya":"Rp30.000","masa_berlaku":"6 bulan"}', 'completed', '2026-07-11 09:01:41.738917+00', 0, 'f6a7b8c9d0e10006'), ('6de6b514-91bc-4030-a182-33bf3593131c', 'BAPENDA', 'Simulasi Perhitungan Denda Pajak Kendaraan Bermotor (PKB) Terlambat', 'Perhitungan denda keterlambatan PKB cukup kompleks karena melibatkan Sanksi Administratif (SA) dan Sumbangan Wajib Dana Kecelakaan Lalu Lintas Jalan (SWDKLLJ), dengan formula yang dapat berubah sesuai kebijakan terbaru. Untuk perhitungan pasti dan akurat, disarankan warga mengecek langsung melalui aplikasi Signal (Samsat Digital Nasional) atau datang ke kantor Samsat/Bapenda terdekat karena nominal dapat bervariasi tergantung jenis kendaraan dan lama keterlambatan.', 'Pajak Daerah', ARRAY['pkb','pajak kendaraan','denda','samsat'], 3, 'id', 'published', 'manual_input', null, null, null, '2026-06-25 09:01:41.738917+00', '2026-07-10 09:01:41.738917+00', 'Penjelasan umum mengenai kompleksitas perhitungan denda PKB dan rekomendasi pengecekan resmi.', ARRAY['pkb','denda pajak kendaraan','samsat digital','signal'], ARRAY['pajak-daerah','kendaraan-bermotor'], ARRAY['Denda pajak motor telat berapa?','Cara hitung denda PKB gimana?'], ARRAY['Perhitungan denda PKB melibatkan sanksi administratif dan SWDKLLJ yang bisa berubah sesuai kebijakan terbaru.','Untuk angka pasti, cek langsung di aplikasi Signal atau kantor Samsat/Bapenda terdekat.'], 70, true, false, true, ARRAY['BAPENDA'], ARRAY['Perda Provinsi Jawa Timur tentang Pajak Kendaraan Bermotor'], 'https://bapenda.bojonegorokab.go.id/pkb', '{"catatan":"nominal denda bervariasi, perlu cek langsung"}', 'completed', '2026-07-10 09:01:41.738917+00', 0, 'c9d0e1f2a3b40009'), ('6eb4aaac-5f67-485e-90dc-3799e8d821f2', 'DISDUKCAPIL', 'Cara Mengurus Akta Kelahiran Anak Baru Lahir', 'Akta kelahiran wajib diurus maksimal 60 hari sejak kelahiran agar tidak dikenakan sidang pengadilan. Dokumen yang dibutuhkan: surat keterangan lahir dari bidan/rumah sakit, buku nikah/akta perkawinan orang tua, KK, dan KTP kedua orang tua. Pengajuan bisa dilakukan online melalui aplikasi Sistem Informasi Administrasi Kependudukan (SIAK) atau langsung ke kantor Disdukcapil. Proses penerbitan gratis dan biasanya selesai dalam 3-7 hari kerja.', 'Kependudukan', ARRAY['akta kelahiran','anak','siak'], 5, 'id', 'published', 'manual_input', null, null, null, '2026-06-12 09:01:41.738917+00', '2026-07-09 09:01:41.738917+00', 'Panduan lengkap syarat dan batas waktu pengurusan akta kelahiran anak di Disdukcapil Bojonegoro.', ARRAY['akta kelahiran','siak','disdukcapil','anak baru lahir'], ARRAY['layanan-publik','administrasi-kependudukan'], ARRAY['Cara buat akta kelahiran gimana?','Batas waktu urus akta kelahiran berapa hari?','Syarat akta lahir apa saja?'], ARRAY['Siapkan surat keterangan lahir, buku nikah orang tua, KK, dan KTP orang tua, lalu ajukan online via SIAK atau ke kantor Disdukcapil.','Wajib diurus maksimal 60 hari sejak lahir, gratis, selesai 3-7 hari kerja.'], 94, true, true, false, ARRAY['DISDUKCAPIL'], ARRAY['UU No. 24 Tahun 2013 tentang Administrasi Kependudukan'], 'https://disdukcapil.bojonegorokab.go.id/layanan/akta-kelahiran', '{"biaya":"gratis","batas_waktu":"60 hari"}', 'completed', '2026-07-09 09:01:41.738917+00', 0, 'a7b8c9d0e1f20007'), ('76f3affe-31c5-4b57-b02f-3e264fe2c52f', 'DISDUKCAPIL', 'Syarat dan Prosedur Pembuatan KTP Elektronik Baru', 'Untuk membuat KTP elektronik (e-KTP) baru bagi warga yang baru berusia 17 tahun, siapkan dokumen berikut: (1) Fotokopi Kartu Keluarga (KK) asli, (2) Surat pengantar dari RT/RW, (3) Akta kelahiran. Datang langsung ke kantor Disdukcapil Kabupaten Bojonegoro untuk perekaman data biometrik (foto, sidik jari, iris mata). Proses pembuatan gratis dan biasanya selesai dalam 7-14 hari kerja. Jam layanan: Senin-Jumat 08.00-15.00 WIB.', 'Kependudukan', ARRAY['ktp','e-ktp','identitas','perekaman'], 5, 'id', 'published', 'manual_input', null, null, null, '2026-06-17 09:01:41.738917+00', '2026-07-15 09:01:41.738917+00', 'Panduan lengkap syarat dan alur pembuatan e-KTP baru untuk warga usia 17 tahun ke atas di Bojonegoro.', ARRAY['e-ktp','ktp baru','perekaman biometrik','disdukcapil bojonegoro'], ARRAY['layanan-publik','administrasi-kependudukan'], ARRAY['Bagaimana cara buat KTP baru?','Syarat bikin e-KTP apa saja?','Berapa lama proses KTP jadi?'], ARRAY['Siapkan fotokopi KK, surat pengantar RT/RW, dan akta kelahiran, lalu datang ke kantor Disdukcapil untuk perekaman.','Prosesnya gratis dan biasanya jadi dalam 7-14 hari kerja.'], 95, true, true, false, ARRAY['DISDUKCAPIL'], ARRAY['Permendagri No. 8 Tahun 2016 tentang Pedoman Penerbitan KTP-el'], 'https://disdukcapil.bojonegorokab.go.id/layanan/ktp', '{"biaya":"gratis","hari_kerja":"Senin-Jumat","jam_layanan":"08.00-15.00"}', 'completed', '2026-07-15 09:01:41.738917+00', 0, 'a1b2c3d4e5f60001'), ('9fe59f3d-a820-471c-b310-a219e08b5efa', 'BPN', 'Prosedur dan Estimasi Biaya Balik Nama Sertifikat Tanah', 'Balik nama sertifikat tanah diperlukan saat terjadi jual beli, hibah, atau warisan. Dokumen dasar yang diperlukan: sertifikat asli, akta jual beli (AJB) dari PPAT, KTP dan KK pemilik baru, serta bukti pelunasan pajak (BPHTB dan PPh). Estimasi biaya bervariasi tergantung Nilai Perolehan Objek Pajak (NPOP), sehingga sebaiknya dikonsultasikan langsung dengan petugas loket BPN atau PPAT untuk perhitungan pasti. Proses balik nama umumnya memakan waktu 14-30 hari kerja.', 'Pertanahan', ARRAY['balik nama','sertifikat tanah','ajb','bphtb'], 3, 'id', 'published', 'manual_input', null, null, null, '2026-06-14 09:01:41.738917+00', '2026-07-06 09:01:41.738917+00', 'Panduan umum dokumen dan estimasi waktu proses balik nama sertifikat tanah di BPN Bojonegoro.', ARRAY['balik nama tanah','ajb','bphtb','bpn bojonegoro'], ARRAY['pertanahan','legalitas'], ARRAY['Syarat balik nama sertifikat apa saja?','Berapa lama proses balik nama tanah?'], ARRAY['Siapkan sertifikat asli, AJB dari PPAT, KTP/KK pemilik baru, dan bukti pelunasan BPHTB serta PPh.','Biaya bervariasi tergantung NPOP; proses biasanya 14-30 hari kerja.'], 82, true, false, true, ARRAY['BPN'], ARRAY['PP No. 24 Tahun 1997 tentang Pendaftaran Tanah'], 'https://bpn.bojonegorokab.go.id/balik-nama', '{"estimasi_waktu":"14-30 hari kerja"}', 'completed', '2026-07-06 09:01:41.738917+00', 0, 'e1f2a3b4c5d60011'), ('d4a89033-f2a5-4f22-bc5b-ee0fa54a11a5', 'DPMPTSP', 'Cara Menyampaikan Pengaduan Terkait Perizinan yang Lambat', 'Jika pengajuan izin usaha mengalami keterlambatan proses melebihi SLA (Service Level Agreement) yang ditentukan, masyarakat dapat menyampaikan pengaduan melalui kanal resmi: hotline DPMPTSP, email pengaduan, atau datang langsung ke bagian pengaduan di kantor DPMPTSP Bojonegoro. Pengaduan akan ditindaklanjuti maksimal 3 hari kerja. Untuk kasus yang kompleks, tim akan menghubungi pemohon untuk klarifikasi lebih lanjut.', 'Pengaduan Layanan', ARRAY['pengaduan','komplain','sla','izin lambat'], 3, 'id', 'published', 'manual_input', null, null, null, '2026-07-05 09:01:41.738917+00', '2026-07-13 09:01:41.738917+00', 'Prosedur menyampaikan pengaduan jika proses perizinan usaha melewati batas waktu standar.', ARRAY['pengaduan dpmptsp','komplain izin','sla perizinan'], ARRAY['pengaduan','perizinan'], ARRAY['Izin usaha saya lama belum jadi, harus bagaimana?','Cara komplain ke DPMPTSP gimana?'], ARRAY['Anda bisa mengadu lewat hotline, email, atau datang langsung ke bagian pengaduan DPMPTSP Bojonegoro.','Pengaduan akan ditindaklanjuti maksimal 3 hari kerja.'], 85, true, false, true, ARRAY['DPMPTSP'], ARRAY['Perbup Bojonegoro tentang Standar Pelayanan Perizinan'], 'https://dpmptsp.bojonegorokab.go.id/pengaduan', '{"sla_tindak_lanjut":"3 hari kerja"}', 'completed', '2026-07-13 09:01:41.738917+00', 0, 'b8c9d0e1f2a30008'), ('d5c27367-c835-4845-8cf3-3eed24729f61', 'POLRES', 'Cara Membuat Surat Laporan Kehilangan Barang/Dokumen', 'Surat Tanda Terima Laporan (STTL) kehilangan diperlukan untuk mengurus penggantian dokumen seperti KTP, STNK, atau BPKB yang hilang. Warga cukup datang ke SPKT (Sentra Pelayanan Kepolisian Terpadu) Polres Bojonegoro terdekat dengan membawa KTP dan menjelaskan kronologi kehilangan. Layanan ini gratis dan bisa selesai dalam waktu kurang dari 1 jam. Surat laporan kehilangan berlaku sebagai bukti sementara sebelum dokumen asli diterbitkan ulang.', 'Keamanan dan Ketertiban', ARRAY['laporan kehilangan','sttl','spkt'], 3, 'id', 'published', 'manual_input', null, null, null, '2026-07-01 09:01:41.738917+00', '2026-07-12 09:01:41.738917+00', 'Panduan pembuatan surat laporan kehilangan dokumen/barang di SPKT Polres Bojonegoro.', ARRAY['laporan kehilangan','sttl','spkt polres bojonegoro'], ARRAY['keamanan','administrasi'], ARRAY['Cara buat laporan kehilangan KTP gimana?','Lapor kehilangan STNK ke mana?'], ARRAY['Datang ke SPKT Polres Bojonegoro terdekat dengan membawa KTP dan jelaskan kronologinya.','Layanan gratis, selesai kurang dari 1 jam, hasilnya berupa Surat Tanda Terima Laporan (STTL).'], 90, true, true, false, ARRAY['POLRES'], ARRAY['Perkap No. 5 Tahun 2010 tentang SPKT'], 'https://polresbojonegoro.jatim.polri.go.id/layanan/laporan-kehilangan', '{"biaya":"gratis","estimasi_waktu":"< 1 jam"}', 'completed', '2026-07-12 09:01:41.738917+00', 0, 'f2a3b4c5d6e70012'), ('e36b5488-387c-4ff1-bff3-b98c51095003', 'DINAS_PENDIDIKAN', 'Pencairan Beasiswa Bojonegoro Tahap 1B (Lanjutan) Tahun 2026', 'Pemerintah Kabupaten Bojonegoro melalui Dinas Pendidikan resmi mencairkan Beasiswa Bojonegoro Tahap 1B (lanjutan) Tahun 2026 dengan total anggaran Rp10,5 miliar untuk 2.670 mahasiswa. Surat Keputusan (SK) Bupati terkait penerima beasiswa diterbitkan pada Senin, 29 Juni 2026. Pencairan untuk kategori Beasiswa Keluarga Miskin, Beasiswa Scientist lanjutan, dan Beasiswa Pondok Pesantren dilakukan pada Jumat, 3 Juli 2026, sementara Beasiswa Scientist dicairkan pada Senin, 6 Juli 2026. Rincian penerima terdiri dari 14 mahasiswa Beasiswa Pondok Pesantren, 113 mahasiswa Beasiswa Keluarga Miskin, 334 mahasiswa Beasiswa Scientist, dan 2.209 mahasiswa program Beasiswa Sepuluh Sarjana per Desa. Dana ditransfer langsung ke rekening masing-masing penerima sebagai penggantian biaya Uang Kuliah Tunggal (UKT) yang telah dibayarkan mahasiswa, bukan untuk membiayai UKT semester berikutnya. Penyaluran tahun ini membutuhkan waktu lebih panjang karena penyesuaian regulasi berdasarkan Peraturan Bupati Bojonegoro Nomor 42 Tahun 2025 terkait persyaratan, mekanisme seleksi, dan verifikasi faktual penerima.', 'Pendidikan', ARRAY['beasiswa','pencairan beasiswa','ukt','sepuluh sarjana per desa'], 5, 'id', 'published', 'manual_input', null, null, null, '2026-07-07 09:01:41.738917+00', '2026-07-16 09:01:41.738917+00', 'Informasi resmi pencairan Beasiswa Bojonegoro Tahap 1B Tahun 2026 senilai Rp10,5 miliar untuk 2.670 mahasiswa, mencakup jadwal SK Bupati dan tahapan pencairan per kategori.', ARRAY['beasiswa bojonegoro 2026','pencairan beasiswa','ukt','sepuluh sarjana per desa','disdik bojonegoro'], ARRAY['pendidikan','bantuan-keuangan'], ARRAY['Beasiswa Pemkab Bojonegoro sudah cair belum?','Kapan beasiswa Bojonegoro 2026 cair?','Beasiswa keluarga miskin sudah ditransfer belum?'], ARRAY['Beasiswa Bojonegoro Tahap 1B Tahun 2026 sudah dicairkan mulai 3 Juli 2026 untuk kategori Keluarga Miskin, Scientist lanjutan, dan Pondok Pesantren, sementara Beasiswa Scientist dicairkan 6 Juli 2026.','SK Bupati terkait penerima terbit 29 Juni 2026, dana ditransfer langsung ke rekening masing-masing dari total 2.670 penerima.'], 93, true, true, false, ARRAY['DINAS_PENDIDIKAN'], ARRAY['Peraturan Bupati Bojonegoro Nomor 42 Tahun 2025'], 'https://bojonegorokab.go.id/berita/pencairan-beasiswa-2026', '{"sk_bupati":"29 Juni 2026","total_dana":"Rp10.500.000.000","total_penerima":2670,"pencairan_tahap_1":"3 Juli 2026","pencairan_scientist":"6 Juli 2026"}', 'completed', '2026-07-16 09:01:41.738917+00', 0, 'a3b4c5d6e7f80013');